@tool
def search_logs(query: str, limit: int = 20,
                format: Literal["summary","full"] = "summary") -> str | list[dict]:
    rows = es.search(query, size=limit)
    if format == "summary":
        # one line per hit, ~30 tokens total
        return "\n".join(f"{r.ts} [{r.level}] {r.msg[:80]}" for r in rows)
    return [r.dict() for r in rows]   # full JSON only when asked

@tool
def search_logs(query: str, limit: int = 50) -> list[dict]:
    return [r.dict() for r in es.search(query, size=limit)]
    # 50 hits * ~80 fields = 5-15k tokens every call
